<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list ref="tgList" :listType="['List']" :IsShowAction="false" :showCheckBox="true" ModuleName="Stage"
            SubModuleCode="Stage" IdentityColumn="STAGE_ID" :HeaderText="$t('Stage')" :ListData="StageData"
            :HeaderData="Headers" :widgets="widgets" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords"
            :SearchFields="leftSearchFields" IsSearchFieldsOnTop="false" SearchPosition="top"
            :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData" :SortExp="SortExp"
            :SortBy="SortBy" :LegendArray="LegendArray" :NorecordfoundText="$t('NoRecordfound')"
            v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick" :Key="Key" :routeInfo="$router"
            v-on:SortdataButtonClick="sortdata">
            <template v-slot:slotdata="{ data }">         
                <template v-if="data.column.COLUMN_NAME == 'STATUS_ID'">
                    <select @change="Updatestatus(data.row.STAGE_ID,data.row.STATUS_ID)" class="w-100 text-center text-white" :style="BIconBorderStyle(data.row.STATUS_ID)"  v-model="data.row.STATUS_ID">
                        <option value="1001" > Active </option>
                        <option value="1002" > Inactive </option>
                    </select>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'STAGE_NAME'">
                    <a class="text-primary" @click="OpenEditModel(data.row)">{{ data.row.STAGE_NAME }}</a>
                </template>
            </template>
        </tg-list>
        <AddNewStage v-if="isShowStageModel" :EditStageData="EditStageData" @CloseStageModel="CloseStageModel">
        </AddNewStage>
    </section>
</template>
<script>
import DataService from '../../../services/DataService';
import StageListSchema from './StageListSchema.js';
import AddNewStage from './AddNewStage.vue';
export default {
    components: { AddNewStage },
    props: {
        projectId: {
            type: String,
            required: true
        }
    },
    data() {
        return {
            Key:0,
            IsAddStage: false,
            isShowStageModel: false,
            isLoading: false,
            TotalRecords: 0,
            ListingData: [],
            listType: ['List'],
            widgets: [],
            Headers: [
                {
                    "COLUMN_NAME": "STAGE_NAME",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('STAGE_NAME'),
                    "DISPLAY_ORDER": 1,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "STAGE_DESC",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('STAGE_DESC'),
                    "DISPLAY_ORDER": 2
                },
                {
                    "COLUMN_NAME": "STATUS_ID",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('STATUS_ID'),
                    "DISPLAY_ORDER": 3,
                    settings: {
                        isInSlot: true
                    }
                }
            ],
            listheaderbuttons: StageListSchema.buttons,
            leftSearchFields: [{
                fieldName: this.$t('STAGE_NAME'),
                fieldType: "text",
                fieldSearchConditionName: [''],
                paramName: "STAGE_NAME",
                isSearch: true,
                value: "",
                listOptions: []
            }],
            isNewDesign: false,
            PageNumber: 1,
            PageSize: 10,
            SortExp: '',
            SortBy: '',
            LegendArray: [],
            StageData: [],
            EditStageData: [],
            searchCondition: '',
            StatusListForListing: [{ STATUS: 'Active', STATUS_ID: 1001, STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#28a745" }, { STATUS: 'Inactive', STATUS_ID: 1002, STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#d72435" }]
            , STAGE_ID: 0,
        }
    },
    created: function () {
        var ths = this;
        ths.FetchData();
    },
    methods: {
        BIconBorderStyle(id){
            if(id==1001){
                return {
                    'background-color' : 'rgb(40, 167, 69)',
                    'color' : 'rgb(255, 255, 255)'
                }
            }
            else{
                return {
                    'background-color' : 'rgb(215, 36, 53)',
                    'color' : 'rgb(255, 255, 255)'
                }
            }
        },
        CloseStageModel() {
            var ths = this;
            ths.isShowStageModel = false;
            ths.FetchData();
        },
       async CheckAssociatePhase(Id)
        {
            debugger
           var vm=this;
           var url=`ProjectId=${0}&Id=${Id}&type=STAGE`;
          await  DataService.CheckAssociatePhaseAndStage(url).then((response)=>{
              if(response !='')
               if(response.data.result =='EXIST')
               {
                vm.ShowAlert(vm.$t('AlreadyExistsInAnotherProject', [vm.$t('Phase')]), "warning", true, vm.$t("Alert"));
                return true;
               }
               else
               {
                return false;
               }
           });
        },
       async Updatestatus(id,statusId)
        {       debugger
            var vm=this;
                   vm.confirmR(this.$t('ConfirmUpdateStatusRecord'),true, this.$t('UpdateCommonStatus'),function(result) { 
                                var VarObject = {
                                    ID: id,
                                    StatusId: statusId,
                                    IsFor: 'TALYGEN_STAGE'
                                }
                                debugger
                                if(vm.CheckAssociatePhase(id))
                                {return}
                                var objectPostString = JSON.stringify(VarObject);
                                DataService.CommonUpdateStatus(objectPostString).then(function (response) {
                                         if (response.data != null) {
                                            if (response.data.status === 'Success') {
                                                vm.ShowAlert(vm.$t("RecordUpdatedSuccessfully"), "success",vm.$t('Alert'));
                                                vm.PrevStatus = vm.StatusId;
                                                if (typeof vm.callbackfunction != 'undefined' && vm.callbackfunction != null) {
                                                    vm.callbackfunction();
                                                }
                                            } else {
                                                vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                                            }
                                        } else {
                                            vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                                        }
                                         
                                    }, function (response) {
                                         debugger
                                    });
                                
                            },function(result) {
                                vm.FetchData();
                            })

        }, 
        async OpenEditModel(data) {
            var vm = this;
            var url = 'controller=Stage&action=Update'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    vm.EditStageData = data;
                    vm.isShowStageModel = true;
                } else {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "AddStage":
                    this.AddPhase();
                    break;
                case "ActiveStage":
                    this.ActiveInActivePhase(0, 'Active');
                    break;
                case "InctiveStage":
                    this.ActiveInActivePhase(0, 'InActive');
                    break;
                case "DeleteStage":
                    this.ActiveInActivePhase(0, 'Delete');
                    break;
            }
        },
        pagerMethod(value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        actionButtonClick() { },
        FetchData: function () {
            var ths = this;
            ths.isLoading = true;
            var url = `search=${ths.searchCondition}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&sortBy=${ths.SortBy}&sortExp=${ths.SortExp}`;
            DataService.GetStageListing(url).then(response => {
                ths.isLoading = false;
                if (response.data.result.Data.length > 0) {
                    ths.StageData = response.data.result.Data;
                    ths.TotalRecords = response.data.result.Data[0].TOTAL;
                    ths.TotalPages = Math.ceil(ths.TotalRecords / ths.PageSize);
                    ths.CurrentPage = ths.PageNumber;
                    ths.listheaderbuttons[1].isdisabled = true;
                    ths.listheaderbuttons[2].isdisabled = true;
                    ths.listheaderbuttons[3].isdisabled = true;
                }
                else {
                    ths.StageData = [];
                    vueObj.TotalPages = 1;
                    ths.TotalRecords = 0;
                }
            });
        },
        renderActions: function () { },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    this.searchCondition = value.searchConditionJson.split('=')[1];
                } else {
                    this.searchCondition = value.searchCondition;
                }
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        async AddPhase() {
            var vm = this;
            var url = 'controller=Stage&action=Add'
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    vm.EditStageData = null;
                    vm.isShowStageModel = true;
                    vm.IsAddStage = true;
                } else {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });
        },
         
        async ActiveInActivePhase(id, type) {
            debugger
            var vm = this;
            var url = `controller=Stage&action=${type == 'Delete' ? 'Delete' : 'UpdateStatus'}`;
            await DataService.CheckPrivilege(url).then(async function (response) {
                if (response.data) {
                    var val = "";
                    vm.isLoading = true;
                    if (id == 0) {
                        $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                            if (val.length > 0)
                                val += ',';
                            val += $(this).val();
                        });
                    } else {
                        val = id;
                    }
                    if (val != null) {
                        vm.confirmR(vm.$t("phaseApproveReject"), true, vm.$t("Stage"), function () {
                            vm.CheckAssociatePhase(val);
                            var refId = 0;
                            if (type == 'Active') {
                                refId = 1001;
                            } else if (type == 'InActive') {
                                refId = 1002;
                            } else if (type == 'Delete') {
                                refId = 1003;
                            }
                            var postJSON = {
                                ids: val,
                                moduleName: 'Stage',
                                subModuleCode: "Stage",
                                refCode: 'PROJCET_TALYGEN_STAGE',
                                refId: refId,
                            };
                            var objectPostString = JSON.stringify(postJSON);
                            DataService.CommonCommonDelete(objectPostString).then(function (response) {
                                vm.isLoading = false;
                                if (response.data[0].Status == "Success") {
                                    if (type == 'Delete') {
                                        vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Status')]), "success", true, vm.$t("Alert"));
                                    }
                                    else {
                                        vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Status')]), "success", true, vm.$t("Alert"));
                                    }
                                    vm.FetchData();
                                    vm.Key++;
                                }
                                else {
                                    vm.ShowAlert(vm.$t('DeleteError'), "warning", true, vm.$t('Alert'));
                                }
                            });
                        });
                    }
                    else {
                        vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
                    }
                    vm.isLoading = false;
                } else {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });
        },
    }
}
</script>